class Solution {
    public int findKthNumber(int n, int k) {
        int num = 1;
        k--;
        while (k > 0) {
            int count = 0;
            for (int i = num; i <= n; i++) {
                if (String.valueOf(i).startsWith(String.valueOf(num))) {
                    count++;
                }
                if (count == k) {
                    return i;
                }
            }
            num++;
        }
        return num;
    }
}
```
